/**
 * Tests for the AkmeEngine
 * Verify that waiting is disciplined
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { AkmeEngine } from './akme.js';
import type { WaitingQuestion } from './types.js';

describe('AkmeEngine', () => {
  let engine: AkmeEngine;

  beforeEach(() => {
    engine = new AkmeEngine();
  });

  describe('threshold detection', () => {
    it('should detect complexity threshold', () => {
      const threshold = engine.detectThreshold(
        'The system has grown too complex',
        ['knot of dependencies', 'intertwined logic']
      );

      expect(threshold).not.toBeNull();
      expect(threshold!.type).toBe('complexity');
      expect(threshold!.confidence).toBeGreaterThan(0.5);
      expect(threshold!.suggestedAction).toBe('simplify');
    });

    it('should detect uncertainty threshold', () => {
      const threshold = engine.detectThreshold(
        'I am not sure which path to take',
        ['multiple options', 'choices unclear']
      );

      expect(threshold).not.toBeNull();
      expect(threshold!.type).toBe('uncertainty');
    });

    it('should detect intuition threshold', () => {
      const threshold = engine.detectThreshold(
        'Something feels wrong about this',
        ['sense of missing', 'not right']
      );

      expect(threshold).not.toBeNull();
      expect(threshold!.type).toBe('intuition');
    });

    it('should return null for unrecognized patterns', () => {
      const threshold = engine.detectThreshold(
        'This is clear and straightforward',
        ['simple', 'direct']
      );

      expect(threshold).toBeNull();
    });

    it('should respect triggerThresholds config', () => {
      const restricted = new AkmeEngine({
        triggerThresholds: ['complexity'],
      });

      const complexity = restricted.detectThreshold(
        'Too complex',
        ['knot'],
      );
      expect(complexity).not.toBeNull();

      const uncertainty = restricted.detectThreshold(
        'I am uncertain',
        ['options'],
      );
      expect(uncertainty).toBeNull();
    });
  });

  describe('suspension lifecycle', () => {
    it('should create a suspension', () => {
      const questions: WaitingQuestion[] = [{
        id: 'q1',
        question: 'What is the pattern?',
        context: 'Testing suspension',
        thresholdType: 'emergence',
        urgency: 'when-ready',
        createdAt: Date.now(),
        catalysts: ['similar patterns', 'new data'],
        blockers: ['insufficient context'],
      }];

      const suspension = engine.suspend(
        'Waiting for pattern to emerge',
        'emergence',
        questions,
        { file: 'test.ts', line: 10 }
      );

      expect(suspension.id).toMatch(/^susp_/);
      expect(suspension.reason).toBe('Waiting for pattern to emerge');
      expect(suspension.questions).toHaveLength(1);

import { describe, it, expect, beforeEach } from 'vitest';
import { MemoryPalace } from './MemoryPalace';
import type { PalaceRoom } from './MemoryPalace';

describe('MemoryPalace', () => {
  let palace: MemoryPalace;

  beforeEach(() => {
    palace = new MemoryPalace();
  });

  describe('addRoom', () => {
    it('should create a room with correct structure', () => {
      const room = palace.addRoom('session_1', {
        timestamp: Date.now(),
        mode: 'flow'
      });

      expect(room.id).toBe('room_session_1');
      expect(room.sessionRef).toBe('session_1');
      expect(room.coordinates).toBeDefined();
      expect(room.texture).toBeDefined();
      expect(room.visited).toBe(false);
    });

    it('should track multiple rooms', () => {
      palace.addRoom('session_1', { timestamp: Date.now() });
      palace.addRoom('session_2', { timestamp: Date.now() });

      expect(palace.getRoomCount()).toBe(2);
    });
  });

  describe('enterRoom', () => {
    it('should mark room as visited', () => {
      palace.addRoom('session_1', { timestamp: Date.now() });

      const room = palace.enterRoom('room_session_1');

      expect(room?.visited).toBe(true);
    });

    it('should return undefined for unknown room', () => {
      const room = palace.enterRoom('room_nonexistent');

      expect(room).toBeUndefined();
    });
  });

  describe('getUnexplored', () => {
    it('should return only unvisited rooms', () => {
      palace.addRoom('session_1', { timestamp: Date.now() });
      palace.addRoom('session_2', { timestamp: Date.now() });

      palace.enterRoom('room_session_1');

      const unexplored = palace.getUnexplored();

      expect(unexplored.length).toBe(1);
      expect(unexplored[0]?.sessionRef).toBe('session_2');
    });
  });

  describe('getByMood', () => {
    it('should filter rooms by mood', () => {
      palace.addRoom('session_1', { mode: 'threshold', timestamp: Date.now() });
      palace.addRoom('session_2', { mode: 'flow', timestamp: Date.now() });

      const threshold = palace.getByMood('threshold');

      expect(threshold.length).toBe(1);
      expect(threshold[0]?.sessionRef).toBe('session_1');
    });
  });

  describe('searchByTheme', () => {
    it('should find rooms by theme', () => {
      palace.addRoom('session_1', {
        timestamp: Date.now(),
        insights: ['Building continuity', 'Threshold crossing']
      });
      palace.addRoom('session_2', {
        timestamp: Date.now() - 1000,
        insights: ['Dream processing']
      });

      const results = palace.searchByTheme('continuity');

      expect(results.length).toBe(1);
      expect(results[0]?.sessionRef).toBe('session_1');
    });
  });
});
