}

export interface PatternRecord {
  type: string;
  confidence: number;
}

export interface FileOperationsRecord {
  reads: string[];
  writes: string[];
  tests: string[];
}

export interface QueryResult<T> {
  count: number;
  items: T[];
  metadata: {
    queryTime: number;
    matchedCriteria: string[];
  };
}

export interface PatternInsight {
  patternType: string;
  frequency: number;
  confidence: number;
  sessions: string[];
}

export interface TemporalSpan {
  start: number;
  end: number;
